/* ======================
     MOUNT CONTAINER
  ====================== */
  #product{
    max-width: 1120px;
    margin: 0 auto;
    padding: 24px 20px;
    box-sizing: border-box;
    font-family: ui-sans-serif, system-ui, -apple-system, "Segoe UI",
      Roboto, Helvetica, Arial, "Apple Color Emoji", "Segoe UI Emoji";
  }

  /* Prevent any child from causing overflow */
#product,
#product *{
  box-sizing: border-box;
}

/* Grid should never exceed container */
#product .jp-grid{
  width: 100%;
}

/* Allow grid items/cards to shrink inside grid */
#product .jp-card{
  min-width: 0;
}

/* Allow flex children to shrink (important for long titles) */
#product .jp-body{
  min-width: 0;
}

/* Wrap long product titles instead of pushing layout */
#product .jp-title{
  overflow-wrap: anywhere;
  word-break: break-word;
}

/* Safety: if any inner element still overflows, clip it */
#product .jp-card{
  overflow: hidden;
}


  /* ======================
     GRID
  ====================== */
  #product .jp-grid{
    display: grid;
    grid-template-columns: 1fr;
    gap: 18px;
  }

  /* ======================
     ≥ 540px
  ====================== */
  @media (min-width: 540px){
    #product{
      padding-left: 20px;
      padding-right: 20px;
    }

    #product .jp-grid{
      grid-template-columns: repeat(2, minmax(0, 1fr));
    }
  }

  /* ======================
     ≥ 840px
  ====================== */
  @media (min-width: 840px){
    #product{
      padding-left: 24px;
      padding-right: 24px;
    }

    #product .jp-grid{
      grid-template-columns: repeat(2, minmax(0, 1fr));
      gap: 20px;
    }
  }

  /* ======================
     ≥ 1024px
  ====================== */
  @media (min-width: 1024px){
    #product{
      max-width: 1200px;
      padding-left: 32px;
      padding-right: 32px;
    }
  }

  /* ======================
     ≥ 1280px (DESKTOP)
  ====================== */
  @media (min-width: 1280px){
    #product{
      max-width: 1320px;
    }

    #product .jp-grid{
      grid-template-columns: repeat(3, minmax(0, 1fr));
      gap: 24px;
    }
  }

  /* ======================
     ≥ 1440px (WIDE)
  ====================== */
  @media (min-width: 1440px){
    #product{
      max-width: 1360px;
    }
  }

  /* ======================
     CARD
  ====================== */
  #product .jp-card{
    background: rgba(255,255,255,0.9);
    border-radius: 18px;
    overflow: hidden;
    display: flex;
    flex-direction: column;
    min-height: 100%;
    border: 1px solid rgba(15, 23, 42, 0.08);
    box-shadow:
      0 12px 28px rgba(0,0,0,0.12),
      0 4px 12px rgba(0,0,0,0.08);
    transition: transform 180ms ease, box-shadow 180ms ease;
  }

  #product .jp-card:hover{
    transform: translateY(-3px);
    box-shadow:
      0 18px 44px rgba(0,0,0,0.16),
      0 6px 18px rgba(0,0,0,0.10);
  }

  /* ======================
     IMAGE
  ====================== */
  #product .jp-media{
    aspect-ratio: 1 / 1;
    background: linear-gradient(
      180deg,
      rgba(0,0,0,0.04),
      rgba(0,0,0,0.00)
    );
  }

  #product .jp-media img{
    width: 100%;
    height: 100%;
    object-fit: cover;
    display: block;
  }

  /* ======================
     BODY
  ====================== */
  #product .jp-body{
    padding: 14px 14px 16px;
    display: flex;
    flex-direction: column;
    gap: 10px;
    flex: 1;
  }

  @media (max-width: 540px){
    #product .jp-body{
      padding: 12px;
      gap: 8px;
    }
  }

  /* ======================
     TEXT
  ====================== */
  #product .jp-title{
    margin: 0;
    font-size: 16px;
    font-weight: 800;
    line-height: 1.3;
    color: #0f172a;
    letter-spacing: 0.01em;
  }

  @media (max-width: 540px){
    #product .jp-title{
      font-size: 15px;
    }
  }

  #product .jp-price{
    font-size: 14px;
    font-weight: 800;
    color: rgba(15, 23, 42, 0.75);
  }

  /* ======================
     BUTTON
  ====================== */
  #product .jp-btn{
    margin-top: auto;
    border: 0;
    cursor: pointer;
    border-radius: 14px;
    padding: 12px 14px;
    font-weight: 900;
    letter-spacing: 0.08em;
    text-transform: uppercase;
    text-align: center;
    text-decoration: none;
    color: #ffffff;

    background: linear-gradient(
      90deg,
      #EC7A5C 0%,
      #F2BE5E 55%,
      rgba(55, 94, 101, 0.40) 100%
    );

    box-shadow:
      0 10px 22px rgba(236, 122, 92, 0.25),
      0 8px 18px rgba(242, 190, 94, 0.22);

    transition: transform 160ms ease, filter 160ms ease;
  }

  #product .jp-btn:hover{
    transform: translateY(-1px);
    filter: brightness(1.05);
  }

  #product .jp-btn:active{
    transform: translateY(0);
    filter: brightness(0.98);
  }

  @media (max-width: 540px){
    #product .jp-btn{
      padding: 10px 12px;
      font-size: 13px;
    }
  }

  /* ======================
     ERROR
  ====================== */
  #product .jp-error{
    margin-top: 12px;
    padding: 12px;
    border-radius: 14px;
    border: 1px solid rgba(239, 68, 68, 0.25);
    background: rgba(239, 68, 68, 0.06);
    font-size: 14px;
    white-space: pre-wrap;
  }
